import React, { useMemo } from 'react';
import {
  LinTreeNav,
  type LinTreeNavNode,
  type LinTreeNavSelection,
} from '@linm-soft-org/linm-web-common-components';
import type { CustomerListNavDto, CustomerListNavNodeDto } from '../../../services/master/models';
import type { CustomerGroupAnalysisType, CustomerGroupNavSelection } from '../../../utils/customerGroupTree';

export type { CustomerGroupNavSelection };

type Props = {
  testIdPrefix: string;
  nav: CustomerListNavDto | null;
  selection: CustomerGroupNavSelection;
  onSelect: (next: CustomerGroupNavSelection) => void;
  /** Sau khi load grid — cập nhật số «Tất cả» (mặc định dùng nav.allRow.count). */
  totalCount?: number;
};

function toLinTreeNavSelection(selection: CustomerGroupNavSelection): LinTreeNavSelection {
  if (selection.kind === 'all') return { kind: 'all' };
  if (selection.kind === 'type') return { kind: 'section', sectionId: selection.customerType };
  return { kind: 'node', nodeId: selection.customerGroupId };
}

function fromLinTreeNavSelection(selection: LinTreeNavSelection): CustomerGroupNavSelection {
  if (selection.kind === 'all') return { kind: 'all' };
  if (selection.kind === 'section') {
    return { kind: 'type', customerType: selection.sectionId as CustomerGroupAnalysisType };
  }
  return { kind: 'group', customerGroupId: selection.nodeId };
}

function mapNavNode(node: CustomerListNavNodeDto): LinTreeNavNode {
  const rowStyle =
    node.level === 1 && (node.backgroundColor || node.fontColor)
      ? {
          backgroundColor: node.backgroundColor ?? undefined,
          color: node.fontColor ?? undefined,
        }
      : undefined;

  return {
    nodeId: node.nodeId,
    code: node.code,
    label: node.label,
    count: node.count,
    level: node.level,
    rowStyle,
    children: node.children.map(mapNavNode),
  };
}

export const CustomerGroupCascadeNav: React.FC<Props> = ({
  testIdPrefix,
  nav,
  selection,
  onSelect,
  totalCount,
}) => {
  const sections = useMemo(
    () => (nav?.sections ?? []).map(s => ({
      sectionId: s.sectionId,
      label: s.label,
      count: s.count,
      nodes: s.nodes.map(mapNavNode),
    })),
    [nav],
  );

  const resolveAncestorNodeIds = useMemo(
    () => (nodeId: string) => nav?.ancestorNodeIdsByNodeId[nodeId] ?? [],
    [nav],
  );

  if (!nav) {
    return (
      <LinTreeNav
        testIdPrefix={testIdPrefix}
        title="Nhóm đối tượng"
        selection={toLinTreeNavSelection(selection)}
        onSelect={next => onSelect(fromLinTreeNavSelection(next))}
        allRow={{ label: 'Tất cả', count: totalCount }}
        sections={[]}
      />
    );
  }

  return (
    <LinTreeNav
      testIdPrefix={testIdPrefix}
      title={nav.title}
      selection={toLinTreeNavSelection(selection)}
      onSelect={next => onSelect(fromLinTreeNavSelection(next))}
      allRow={{
        label: nav.allRow.label,
        count: totalCount ?? nav.allRow.count,
      }}
      sections={sections}
      defaultExpandedSectionIds={nav.defaultExpandedSectionIds}
      resolveAncestorNodeIds={resolveAncestorNodeIds}
    />
  );
};
